import { type ReactNode, useReducer } from "react";
import { AppBar, Container, CssBaseline, Grid } from "@mui/material";

import Theme from "./Theme";

import {
	AppDispatchContext,
	AppStateContext,
	getDefaultState,
} from "./context";

import appReducer from "./reducer";

import MetadataEditor from "./components/editor/MetadataEditor";
import LayersList from "./components/editor/layers/LayersList";
import Renderer from "./components/renderer";

function App() {
	return (
		<Theme>
			<CssBaseline />
			<AppBar
				position="static"
				sx={{ padding: 2, fontSize: "24px", textAlign: "center" }}
			>
				Groovy Text
			</AppBar>
			<Container maxWidth="md" sx={{ marginTop: 4 }}>
				<AppContext>
					<Grid container spacing={4}>
						<Grid size={{ xs: 12 }}>
							<MetadataEditor />
						</Grid>

						<Grid size={{ xs: 12, md: 6 }}>
							<LayersList />
						</Grid>

						<Grid size={{ xs: 12, md: 6 }}>
							<Renderer />
						</Grid>
					</Grid>
				</AppContext>
			</Container>
		</Theme>
	);
}

const AppContext = ({ children }: { children: ReactNode }) => {
	const [state, dispatch] = useReducer(appReducer, getDefaultState());

	return (
		<AppDispatchContext.Provider value={dispatch}>
			<AppStateContext.Provider value={state}>
				{children}
			</AppStateContext.Provider>
		</AppDispatchContext.Provider>
	);
};

export default App;
